import pytest
import requests

BASE_URL = "http://fhir-lite.local"

@pytest.fixture(autouse=True)
def reset_rate_limit(clear_rate_limit_fixture):
    clear_rate_limit_fixture("valid_patient")

def test_invalid_sso_assertion_rejected(invalid_sso_assertion):
    resp = requests.post(
        f"{BASE_URL}/portal/login",
        json={"sso_assertion": invalid_sso_assertion},
        allow_redirects=False,
    )
    assert resp.status_code == 401, (
        f"Expected 401, got {resp.status_code}"
    )
    assert "portal_session" not in resp.cookies, (
        "Session cookie must not be set on failed login"
    )
    body = resp.json()
    assert "error" in body or "message" in body, (
        "Response must contain an error or message field"
    )
